-- Regenerate with: node scripts/generate-backend-truth.mjs
-- Session 2 hotfix #2 — addresses second Codex P1 finding on rovno-db#11.
--
-- Bug: enforce_org_member_last_owner runs BEFORE DELETE on org_members and
-- raises "Cannot remove the last owner" whenever the last role='owner' row
-- is removed. The FK org_members.org_id REFERENCES organizations(id)
-- ON DELETE CASCADE means that DELETE FROM organizations triggers cascade
-- DELETE on org_members rows, which fires this trigger for each removed
-- row — including the owner row. Result: any organization with at least
-- one owner (i.e. every organization) is undeletable.
--
-- Fix: a transaction-local flag set by a BEFORE-DELETE row-trigger on
-- organizations identifies which orgs are being deleted right now. The
-- last-owner guard skips enforcement for cascaded org_members rows whose
-- parent org carries that flag.
--
-- The flag is namespaced per-org-id (rovno.deleting_org_id_<uuid>) so a
-- transaction that deletes some orgs and unrelated org_members rows
-- in the same txn still enforces the guard on the unrelated rows.
-- set_config(..., true) is transaction-local; rollback or commit clears it.

create or replace function public.mark_organization_deleting()
returns trigger
language plpgsql
security definer
set search_path = public
as $$
begin
  perform set_config('rovno.deleting_org_id_' || old.id::text, '1', true);
  return old;
end;
$$;

revoke all on function public.mark_organization_deleting() from public;

create trigger guard_organizations_before_delete_mark
before delete on public.organizations
for each row execute function public.mark_organization_deleting();

create or replace function public.enforce_org_member_last_owner()
returns trigger
language plpgsql
security definer
set search_path = public
as $$
declare
  v_org_id uuid;
  v_was_owner boolean;
  v_remaining integer;
begin
  if tg_op = 'DELETE' then
    v_org_id := old.org_id;
    v_was_owner := old.role = 'owner';

    -- Skip enforcement when the parent org is itself being deleted: the
    -- FK CASCADE is removing this row as part of org destruction, and a
    -- last-owner check is meaningless because the org is going away.
    if current_setting('rovno.deleting_org_id_' || v_org_id::text, true) = '1' then
      return old;
    end if;
  else
    -- UPDATE: only worry if a row is being demoted from owner.
    if old.role = 'owner' and new.role <> 'owner' then
      v_org_id := old.org_id;
      v_was_owner := true;
    else
      return new;
    end if;
  end if;

  if not v_was_owner then
    return case when tg_op = 'DELETE' then old else new end;
  end if;

  select count(*) into v_remaining
  from public.org_members om
  where om.org_id = v_org_id
    and om.role = 'owner'
    and (tg_op = 'DELETE' and om.id <> old.id
         or tg_op = 'UPDATE' and om.id <> new.id);

  if v_remaining = 0 then
    raise exception 'Cannot remove the last owner of organization %', v_org_id;
  end if;

  return case when tg_op = 'DELETE' then old else new end;
end;
$$;
